// Grok API research with web scraping
const { runResearch } = require('./n8n/step1-research.js');
const result = await runResearch({ category: null });
return [{ json: result }];

// Grok API content generation
const { generateContent } = require('./n8n/step2-content.js');
const input = $input.first().json;
const result = await generateContent(input);
return [{ json: result }];

// Replicate Seedream-4 image generation
const { generateImages } = require('./n8n/step3-images.js');
const input = $input.first().json;
const outputDir = `/tmp/pom-slideshow-${Date.now()}`;
const result = await generateImages(input, outputDir);
return [{ json: { ...result, outputDir } }];

// Sharp text overlay compositing
const { addOverlays } = require('./n8n/step4-overlays.js');
const input = $input.first().json;
const result = await addOverlays(input, input.outputDir + '/final');
return [{ json: { ...input, ...result } }];

// Android emulator screenshot capture
const { captureScreenshots } = require('./n8n/step5-screenshots.js');
const input = $input.first().json;
const result = await captureScreenshots(input, input.outputDir + '/screenshots');
return [{ json: { ...input, ...result } }];

// Generate HTML preview with download/copy buttons
const { generatePreview } = require('./n8n/step6-preview.js');
const input = $input.first().json;
const result = await generatePreview(input);
return [{ json: result }];
